export type BlogKind='guide'|'model'|'comparison'|'system'|'installation';
export interface Blog {slug:string;title:string;description:string;primaryKeyword:string;kind:BlogKind;category:string;answer:string;focus:string;contrast:string;model:string;productSlug:string;checklist:string[];insights:string[];featuredAlt:string;inlineAlt:string;}

export const blogs: Blog[]=[
{slug:'transformer-oil-temperature-indicator-guide',title:'Transformer Oil Temperature Indicator Guide',description:'Learn how transformer oil temperature indicators measure top oil, control cooling, send remote signals and support oil-immersed transformer selection.',primaryKeyword:'transformer oil temperature indicator',kind:'guide',category:'Fundamentals',answer:'A transformer oil temperature indicator, or OTI, measures the temperature of insulating oil at a thermometer pocket in the upper oil region. It provides a local dial and can operate adjustable contacts for cooling or alarm. Selected models also provide Pt100 or 4-20 mA remote outputs.',focus:'top-oil measurement, local indication and cooling control',contrast:'an OTI measures oil temperature and does not directly measure conductor hot-spot temperature',model:'BWY2 and BWY-802/803',productSlug:'bwy2-transformer-oil-temperature-indicator',checklist:['Required temperature scale','Number and duty of contacts','Pt100 or 4-20 mA output','Bulb and M27 × 2 thread','Capillary length and route','Outdoor protection requirement'],insights:['The sensing bulb belongs in the specified thermometer pocket, not loose in the transformer tank.','Top oil is a thermal reference for cooling control but remains different from simulated winding temperature.','A remote value needs a defined signal scale and a compatible receiving instrument.','Contact settings should follow transformer thermal engineering data.','Capillary protection is a mechanical reliability requirement.','The complete suffix identifies the usable product configuration.'],featuredAlt:'Oil temperature indicator beside an oil-immersed power transformer',inlineAlt:'Engineer inspecting a transformer top-oil temperature sensing pocket'},
{slug:'transformer-winding-temperature-indicator-guide',title:'Transformer Winding Temperature Indicator Guide',description:'Understand transformer winding temperature indicators, thermal simulation, CT input, cooling contacts, remote output and BWR model selection.',primaryKeyword:'transformer winding temperature indicator',kind:'guide',category:'Fundamentals',answer:'A transformer winding temperature indicator, or WTI, combines measured top-oil temperature with a calibrated heating effect related to transformer load current. The resulting pointer value represents simulated winding temperature and can operate cooling, alarm or trip contacts.',focus:'simulated winding temperature, load-current compensation and protection contacts',contrast:'a traditional WTI estimates winding temperature and is not the same as a direct embedded hot-spot sensor',model:'BWR2 and BWR-04/06',productSlug:'bwr2-transformer-winding-temperature-indicator',checklist:['CT secondary current and converter','Temperature range','Cooling, alarm and trip contacts','Pt100 or 4-20 mA output','Capillary and compound transmitter','Existing wiring for replacement'],insights:['With no load, a traditional WTI follows transformer top-oil temperature.','Load current drives a heating element that adds a simulated winding-to-oil rise.','The CT and converter characteristics are part of the measurement system.','Each switch must have a documented control function.','Remote indication must preserve the same scale as the local instrument.','Retrofit selection requires both mechanical and CT-circuit information.'],featuredAlt:'Winding temperature indicator and transformer load current concept',inlineAlt:'Transformer engineer reviewing winding temperature control circuits'},
{slug:'oti-vs-wti-transformer',title:'OTI vs WTI for Oil-Immersed Transformers',description:'Compare transformer OTI and WTI functions, measured values, contacts, installation and outputs before selecting oil and winding temperature indicators.',primaryKeyword:'OTI vs WTI transformer',kind:'comparison',category:'Selection',answer:'OTI means oil temperature indicator and measures transformer top-oil temperature. WTI means winding temperature indicator and adds a load-current thermal simulation to the top-oil value. Both can provide local indication, contacts and remote outputs, but they represent different thermal variables.',focus:'choosing the correct oil or winding temperature variable',contrast:'OTI reports top oil while WTI reports a simulated load-dependent winding value',model:'BWY2 compared with BWR2',productSlug:'bwr2-transformer-winding-temperature-indicator',checklist:['Which temperature must be shown','Cooling control ownership','Alarm and trip philosophy','Need for CT input','Remote signal and scale','Thermometer pocket arrangement'],insights:['An OTI can start cooling based on top-oil temperature.','A WTI usually needs a CT-derived input for thermal simulation.','The two instruments can be installed together on the same transformer.','Operator displays should label each value clearly.','Set points are not transferable between the two variables.','Direct fiber-optic winding measurement is a third, separate method.'],featuredAlt:'Side-by-side oil and winding temperature indicators for comparison',inlineAlt:'Diagram concept comparing top-oil and simulated winding temperature'},
{slug:'bwr2-winding-temperature-indicator-selection',title:'BWR2 Winding Temperature Indicator Selection',description:'Select a BWR2 winding temperature indicator by range, switch contacts, CT input, Pt100 or 4-20 mA output, capillary and remote display.',primaryKeyword:'BWR2 winding temperature indicator',kind:'model',category:'Model Guides',answer:'BWR2 selection requires more than the family name. Confirm the full model suffix, 0-160°C range requirement, four contact functions, CT secondary current, Pt100 or 4-20 mA output, capillary length, compound transmitter and remote display before ordering.',focus:'turning a BWR2 family request into a controlled model configuration',contrast:'different BWR2 suffixes can look similar while using different output and contact arrangements',model:'BWR2-04 and BWR2-06 variants',productSlug:'bwr2-transformer-winding-temperature-indicator',checklist:['Complete BWR2 suffix','Four contact assignments','CT current and heating curve','Pt100 or transmitter output','Capillary length code','Environmental suffix and mounting'],insights:['The referenced BWR2 range is 0-160°C with Class 1.5 accuracy.','Four adjustable contacts can serve cooling, alarm and trip logic.','The stated switch rating is AC 220 V / 5 A.','Protection is referenced as IP55.','Capillary length follows the selected instrument number.','Final dimensions must be checked on the current drawing.'],featuredAlt:'BWR2 winding temperature indicator prepared for technical selection',inlineAlt:'Engineer comparing BWR2 model codes and transformer drawings'},
{slug:'bwy2-oil-temperature-indicator-selection',title:'BWY2 Oil Temperature Indicator Selection Guide',description:'Select a BWY2 oil temperature indicator by range, contacts, Pt100 output, bulb, M27 × 2 thread, capillary length and remote display options.',primaryKeyword:'BWY2 oil temperature indicator',kind:'model',category:'Model Guides',answer:'BWY2 selection starts with the top-oil scale and contact requirement. Confirm the full model, -20-140°C range, two to four contacts, Pt100 or optional transmitter output, Φ14 × 150 mm bulb, M27 × 2 thread, capillary length and mounting drawing.',focus:'selecting the BWY2 OTI configuration for local and remote oil temperature control',contrast:'the dial family name does not define the final switch count or remote output',model:'BWY2-804 and BWY2-806 variants',productSlug:'bwy2-transformer-oil-temperature-indicator',checklist:['Complete BWY2 model suffix','Top-oil temperature scale','Two to four contact functions','Pt100 or transmitter output','Bulb, thread and pocket','Capillary and mounting position'],insights:['The referenced ambient range extends from -40°C to +80°C.','The referenced measuring scale is -20°C to 140°C.','The bulb is Φ14 × 150 mm with M27 × 2 mounting thread.','The stated switch rating is AC 220 V / 5 A.','Protection is referenced as IP55.','A remote display is an option that must match the field output.'],featuredAlt:'BWY2 transformer oil temperature indicator on a clean technical bench',inlineAlt:'Top-oil thermometer bulb and capillary installation concept'},
{slug:'bwr-04-vs-bwr-06-winding-temperature-controller',title:'BWR-04 vs BWR-06 Winding Controllers',description:'Compare BWR-04 and BWR-06 transformer winding temperature controllers by model suffix, scale, contacts, output, CT input and retrofit requirements.',primaryKeyword:'BWR-04 vs BWR-06',kind:'comparison',category:'Model Guides',answer:'BWR-04 and BWR-06 are winding temperature controller families with several suffix configurations. A reliable comparison uses the full model code, contact quantity, CT input, output signal, supply, scale, capillary and mechanical drawing rather than assuming the family numbers are interchangeable.',focus:'comparing two BWR winding controller families for new and replacement work',contrast:'a family-number match alone cannot prove wiring or mechanical interchangeability',model:'BWR-04 and BWR-06',productSlug:'bwr-04-06-winding-temperature-controller',checklist:['Existing full model code','0-150°C or 0-160°C scale','Contact quantity and duty','4-20 mA or other output','CT converter requirement','Mounting and capillary match'],insights:['The referenced BWR-04J(TH) provides a 4-20 mA output.','The default scale is 0-150°C with 0-160°C optional.','The referenced bulb is Φ14 × 150 mm.','The mounting thread is M27 × 2.','The standard referenced capillary is 5 m.','A retrofit requires terminal-by-terminal comparison.'],featuredAlt:'BWR-04 and BWR-06 winding temperature controller comparison',inlineAlt:'Technician checking BWR winding controller terminals and capillary'},
{slug:'bwy-802-bwy-803-oil-temperature-controller',title:'BWY-802 and BWY-803 Oil Temperature Control',description:'Review BWY-802 and BWY-803 transformer oil temperature controller ranges, Pt100 output, contacts, IP55 protection, bulb and capillary selection.',primaryKeyword:'BWY-802 BWY-803 oil temperature controller',kind:'model',category:'Model Guides',answer:'BWY-802 and BWY-803 oil temperature controllers provide local top-oil indication, adjustable contacts and a Pt100 remote signal. Referenced ranges are 0-100°C or 0-120°C with an M27 × 2 bulb connection and a standard 5 m capillary.',focus:'selecting a BWY-802 or BWY-803 for top-oil indication and remote Pt100 transmission',contrast:'the local mechanical controller and any remote signal converter have separate interface requirements',model:'BWY-802 and BWY-803',productSlug:'bwy-802-803-oil-temperature-controller',checklist:['0-100°C or 0-120°C range','Pt100 receiving input','Switch contact rating','Bulb insertion depth','M27 × 2 thread','5 m or project capillary length'],insights:['The stated 0-120°C accuracy limit is ±1.8°C at the detection point.','The referenced switch error is ±2°C.','The stated contact rating is AC 220 V / 3 A.','Protection is referenced as IP55.','Insertion depth should be at least 150 mm.','Optional signal conversion can add 4-20 mA or RS485.'],featuredAlt:'BWY-802 and BWY-803 oil temperature controller product view',inlineAlt:'Pt100 remote oil temperature signal connection concept'},
{slug:'bwy-d804aith-digital-oil-temperature-controller',title:'BWY-D804AITH Digital Oil Temperature Control',description:'Understand BWY-D804AITH transformer oil temperature controller ranges, four or six contacts, Pt100, 4-20 mA, power, dimensions and capillary options.',primaryKeyword:'BWY-D804AITH',kind:'model',category:'Model Guides',answer:'BWY-D804AITH is a transformer oil temperature controller configuration with local indication, four or six adjustable contacts and Pt100 or 4-20 mA signal options. Referenced scales include 0-150°C, 0-160°C, -20-140°C and -45-150°C.',focus:'specifying a multi-contact digital-capable oil temperature controller',contrast:'the contact quantity, output, power and scale must be defined as one configuration',model:'BWY-D804AITH',productSlug:'bwy-d804aith-digital-oil-temperature-controller',checklist:['Selected temperature scale','Four or six contacts','Pt100 and 4-20 mA requirement','AC/DC supply configuration','6 m or custom capillary','Enclosure mounting dimensions'],insights:['The referenced enclosure is 304 × 192 × 103 mm.','The stated switching error is ±2°C.','The switch differential is stated as 5 ±3°C.','The referenced bulb is Φ14 × 150 mm.','Protection is referenced as IP55.','A remote display can add 4-20 mA and RS485 functions.'],featuredAlt:'BWY-D804AITH digital oil temperature controller for transformers',inlineAlt:'Remote display and oil temperature controller integration concept'},
{slug:'transformer-oil-temperature-monitoring-system',title:'Transformer Oil Temperature Monitoring System',description:'Plan a transformer oil temperature monitoring system using local OTI indication, contacts, Pt100, 4-20 mA or RS485 and remote alarm integration.',primaryKeyword:'transformer oil temperature monitoring system',kind:'system',category:'Monitoring Systems',answer:'A transformer oil temperature monitoring system combines a top-oil sensing point, local or digital instrument, control contacts and a remote interface. The system can use Pt100, 4-20 mA or RS485, but the field device and receiving equipment must share the same scale and wiring definition.',focus:'designing the complete measurement path from oil pocket to control room',contrast:'a sensor value becomes a monitoring system only when indication, alarm, communications and records are coordinated',model:'BWY2, BWY-D804AITH and integrated monitoring devices',productSlug:'oil-temperature-level-pressure-monitoring-device',checklist:['Top-oil sensing location','Local display requirement','Cooling and alarm contacts','Remote interface type','Receiving-system scaling','Loss-of-signal behavior'],insights:['The thermometer pocket defines the physical measurement point.','Local indication remains useful when communications are unavailable.','A current loop needs a documented temperature scale.','RS485 needs protocol and register control.','Alarm logic can live locally or in the supervisory system.','Commissioning must compare field and remote values.'],featuredAlt:'Transformer oil temperature monitoring system in a substation',inlineAlt:'Oil temperature signal path from transformer to control room'},
{slug:'oil-immersed-transformer-winding-temperature-monitoring',title:'Oil-Immersed Transformer Winding Monitoring',description:'Compare simulated WTI and direct sensing approaches for oil-immersed transformer winding temperature monitoring, cooling, alarm and remote indication.',primaryKeyword:'oil immersed transformer winding temperature monitoring',kind:'system',category:'Monitoring Systems',answer:'Oil-immersed transformer winding temperature monitoring can use a traditional WTI that simulates winding temperature from top oil and load current, or a direct embedded sensing method designed into the winding. The methods produce different evidence and must be named correctly.',focus:'choosing between traditional simulated WTI and direct winding temperature measurement',contrast:'thermal simulation supports protection control while direct sensing measures a physical winding location',model:'BWR2 WTI and direct embedded sensing systems',productSlug:'bwr2-transformer-winding-temperature-indicator',checklist:['Required measurement meaning','Transformer design stage','CT and simulation curve','Direct probe feasibility','Cooling and protection outputs','Historical trending requirement'],insights:['Traditional WTI is established for cooling and protection logic.','Direct embedded measurement usually requires design-stage integration.','A single direct point does not describe every winding location.','Simulation quality depends on transformer-specific current conversion.','Operator labels must distinguish measured and simulated values.','Both approaches can contribute to thermal understanding.'],featuredAlt:'Oil-immersed transformer winding temperature monitoring concept',inlineAlt:'Transformer winding thermal paths and monitoring locations'},
{slug:'transformer-top-oil-temperature-monitoring',title:'Transformer Top-Oil Temperature Monitoring',description:'Understand transformer top-oil temperature measurement points, OTI selection, cooling contacts, remote output, installation and operating interpretation.',primaryKeyword:'transformer top oil temperature monitoring',kind:'guide',category:'Monitoring Systems',answer:'Transformer top-oil temperature monitoring measures the oil near the upper region of an oil-filled transformer, where heated oil collects before cooling. A bulb in a thermometer pocket drives a local OTI and can support cooling contacts or a remote signal.',focus:'measuring and interpreting top-oil temperature at the correct pocket',contrast:'top oil is a system thermal indicator and not a direct reading of the hottest winding conductor',model:'BWY2 and BWY oil temperature indicators',productSlug:'bwy2-transformer-oil-temperature-indicator',checklist:['Thermometer pocket location','Bulb insertion depth','Temperature range','Cooling set points','Remote trend signal','Ambient and loading context'],insights:['Pocket location and thermal coupling affect response.','Top-oil trends should be read with load and ambient conditions.','Cooling operation changes the temperature trajectory.','A dial and remote value should use the same scale.','Unexpected temperature rise requires broader transformer assessment.','The OTI contact mechanism needs periodic functional checks.'],featuredAlt:'Top-oil temperature monitoring on a power transformer tank',inlineAlt:'Transformer oil circulation and upper temperature sensing region'},
{slug:'transformer-temperature-controller-wiring',title:'Transformer Temperature Controller Wiring Guide',description:'Plan transformer temperature controller wiring for adjustable contacts, Pt100, 4-20 mA, power, CT input and RS485 without mixing incompatible circuits.',primaryKeyword:'transformer temperature controller wiring',kind:'installation',category:'Installation',answer:'Transformer temperature controller wiring separates dry switch contacts, Pt100 resistance signals, powered 4-20 mA loops, WTI current-transformer inputs and RS485 communications. Use the exact model terminal diagram because similar enclosures can contain different electrical configurations.',focus:'creating a terminal-by-terminal wiring plan for OTI, WTI and monitoring devices',contrast:'contacts, resistance outputs, current loops and digital communications cannot be wired as interchangeable signal types',model:'BWY, BWR and powered monitoring devices',productSlug:'bwr-04-06-winding-temperature-controller',checklist:['Model-specific terminal diagram','Contact voltage and relay load','Pt100 wire arrangement','4-20 mA polarity and supply','WTI CT circuit safety','RS485 topology and shielding'],insights:['Dry contacts need an external control circuit.','Pt100 circuits require compatible excitation and lead compensation.','A 4-20 mA loop has polarity and resistance limits.','CT secondary circuits require controlled safety procedures.','RS485 needs address, termination and register data.','Every field-to-panel loop should be commissioned end to end.'],featuredAlt:'Transformer temperature controller terminal wiring inspection',inlineAlt:'Separate contact Pt100 current loop and RS485 cable paths'},
{slug:'transformer-temperature-alarm-trip-cooling-contacts',title:'Transformer Alarm, Trip and Cooling Contacts',description:'Coordinate transformer temperature indicator contacts for fan or pump cooling stages, high-temperature alarm and trip logic using verified set points.',primaryKeyword:'transformer temperature alarm trip cooling contacts',kind:'system',category:'Control',answer:'Transformer temperature contacts are adjustable switches in an OTI or WTI that change state at configured values. Projects can assign them to cooling stages, high-temperature alarm or trip input, subject to contact rating, switching differential and approved thermal set points.',focus:'assigning and testing temperature switch contacts in transformer control logic',contrast:'the pointer set point, actual switch action and release temperature are related but not identical',model:'two-contact, four-contact and six-contact instruments',productSlug:'bwy-d804aith-digital-oil-temperature-controller',checklist:['Contact function schedule','Rising set point','Switching differential','Interposing relay requirement','Alarm and trip coordination','Functional test record'],insights:['Direct motor switching may exceed an instrument contact duty.','Cooling stages should operate before alarm or trip according to design.','Mechanical switches include a release differential.','Set points come from transformer engineering data.','Contact state must be tested through the final circuit.','The commissioning record should preserve approved settings.'],featuredAlt:'Transformer cooling alarm and trip contact control panel',inlineAlt:'Temperature contact sequence for cooling alarm and trip'},
{slug:'pt100-vs-4-20ma-transformer-temperature',title:'Pt100 vs 4-20 mA for Transformer Temperature',description:'Compare Pt100 and 4-20 mA transformer temperature signals by wiring, power, distance, scaling, diagnostics and receiving-system compatibility.',primaryKeyword:'Pt100 vs 4-20mA transformer temperature',kind:'comparison',category:'Signals',answer:'Pt100 is a resistance-based temperature signal that the receiving instrument must excite and linearize. A 4-20 mA output is a powered, conditioned current loop mapped to a defined temperature range. Neither is universally better; compatibility, distance, diagnostics and project standards decide.',focus:'selecting the correct analog interface for remote transformer temperature',contrast:'Pt100 preserves a sensor resistance while 4-20 mA transmits a scaled process value',model:'BWY and BWR remote outputs',productSlug:'bwy2-transformer-oil-temperature-indicator',checklist:['Receiving input type','Two, three or four-wire Pt100','Loop power responsibility','4-20 mA temperature scale','Cable length and interference','Open-circuit diagnostic behavior'],insights:['Pt100 lead resistance matters unless compensated.','A current loop can be easier to supervise over longer cable runs.','The 4 mA live zero can indicate a powered loop condition.','Signal conversion adds another calibrated component.','Scaling belongs in the loop diagram and control database.','Isolation and grounding follow the system design.'],featuredAlt:'Pt100 and 4-20 mA transformer temperature signal comparison',inlineAlt:'Engineer testing analog transformer temperature signal loops'},
{slug:'rs485-transformer-temperature-monitoring',title:'RS485 Transformer Temperature Monitoring Guide',description:'Plan RS485 transformer temperature monitoring with protocol, register map, addressing, topology, shielding, power and end-to-end commissioning checks.',primaryKeyword:'RS485 transformer temperature monitoring',kind:'system',category:'Signals',answer:'RS485 provides the physical serial communication layer for transformer temperature monitoring. A usable project also needs the protocol, baud rate, parity, address, register map, scaling, byte order, topology, termination and receiving-system configuration.',focus:'turning an RS485 port into a documented and maintainable monitoring link',contrast:'an RS485 terminal alone does not define Modbus registers or data meaning',model:'integrated oil temperature level pressure monitoring device',productSlug:'oil-temperature-level-pressure-monitoring-device',checklist:['Protocol and register map','Device address and baud rate','Two-wire topology','Termination and biasing','Shield and grounding practice','Loss-of-communication alarm'],insights:['RS485 describes electrical communication rather than the complete application protocol.','Daisy-chain topology is generally easier to control than star wiring.','Termination belongs at the physical ends of the bus.','Each temperature register needs unit and scale.','The powered field device needs a maintained DC supply.','Commissioning should test both values and communication failure.'],featuredAlt:'RS485 transformer monitoring network in a substation',inlineAlt:'Digital transformer temperature register and communication concept'},
{slug:'transformer-thermometer-pocket-installation',title:'Transformer Thermometer Pocket Installation',description:'Install transformer temperature indicator bulbs in thermometer pockets using correct location, insertion depth, thermal interface, sealing and maintenance access.',primaryKeyword:'transformer thermometer pocket installation',kind:'installation',category:'Installation',answer:'A transformer thermometer pocket is a sealed well that allows an OTI or WTI sensing bulb to follow oil temperature without exposing the capillary system directly to transformer oil. Correct location, depth, thermal coupling, sealing and bulb retention affect response and serviceability.',focus:'installing a temperature bulb in a controlled transformer oil pocket',contrast:'the sensing bulb must match the pocket rather than being forced into an unsuitable opening',model:'Φ14 bulb and M27 × 2 arrangements',productSlug:'bwy2-transformer-oil-temperature-indicator',checklist:['Pocket location in top oil','Internal diameter and depth','Bulb diameter and length','Thread and adapter','Thermal coupling medium','Retention and service access'],insights:['The bulb should reach the intended active region of the pocket.','An air gap can slow thermal response.','Adapters must preserve sealing and insertion depth.','The capillary connection needs strain relief.','Pocket dimensions belong on the transformer drawing.','Service access should not require unsafe capillary movement.'],featuredAlt:'Transformer thermometer pocket and sensing bulb installation',inlineAlt:'Close view of temperature bulb insertion into transformer pocket'},
{slug:'transformer-temperature-controller-capillary-installation',title:'Transformer Temperature Controller Capillary Guide',description:'Route and protect transformer temperature controller capillaries with correct length, bend radius, support, vibration control and spare-length management.',primaryKeyword:'transformer temperature controller capillary installation',kind:'installation',category:'Installation',answer:'A transformer temperature controller capillary carries the sensing-medium response between the bulb and the instrument. It must not be cut, kinked, crushed or bent sharply. Select enough length for the route, support it against vibration and coil only the approved spare length.',focus:'protecting the sealed capillary system from installation and service damage',contrast:'a capillary is part of the measuring system and not ordinary cable that can be shortened on site',model:'5 m and 6 m standard capillary configurations',productSlug:'bwr-04-06-winding-temperature-controller',checklist:['Measured route length','Minimum bend radius','Stainless protective hose','Support intervals','Door and panel movement','Spare-length coil location'],insights:['A hidden kink can change instrument response.','Tight coils concentrate stress.','The route should avoid hot surfaces and sharp edges.','Transport restraints must be removed carefully.','Extra length should be managed without flattening the tube.','Replacement selection must include the existing route length.'],featuredAlt:'Protected capillary route on an oil-immersed transformer',inlineAlt:'Technician securing temperature controller capillary tubing'},
{slug:'m27x2-transformer-temperature-sensor-thread',title:'M27 × 2 Transformer Temperature Sensor Thread',description:'Check M27 × 2 transformer temperature bulb mounting threads, pocket compatibility, insertion depth, adapters, sealing and retrofit measurements.',primaryKeyword:'M27x2 transformer temperature sensor thread',kind:'installation',category:'Installation',answer:'M27 × 2 identifies a metric thread with a nominal 27 mm diameter and 2 mm pitch. It appears on referenced transformer temperature bulb arrangements, but thread name alone does not confirm pocket fit. Check engagement, sealing, shoulder, bulb diameter and insertion depth.',focus:'verifying the mechanical interface between temperature bulb and transformer pocket',contrast:'matching the thread designation does not guarantee the same bulb geometry or sealing surface',model:'M27 × 2 with Φ14 × 150 mm bulb',productSlug:'bwy-802-803-oil-temperature-controller',checklist:['Thread diameter and pitch','Male or female interface','Sealing face or washer','Bulb diameter','Insertion depth','Adapter material and oil compatibility'],insights:['Pitch should be measured rather than guessed from diameter.','An adapter changes insertion depth.','The sealing method must suit transformer oil service.','Bulb clearance should avoid mechanical binding.','Drawings should show the shoulder and active length.','Retrofit measurements should be recorded before ordering.'],featuredAlt:'M27 × 2 transformer temperature sensor threaded connection',inlineAlt:'Mechanical inspection of thermometer pocket thread and bulb'},
{slug:'transformer-temperature-indicator-troubleshooting',title:'Transformer Temperature Indicator Troubleshooting',description:'Troubleshoot transformer OTI and WTI pointer error, contact problems, remote signal mismatch, capillary damage and installation issues using safe checks.',primaryKeyword:'transformer temperature indicator troubleshooting',kind:'installation',category:'Maintenance',answer:'Troubleshooting a transformer temperature indicator starts by identifying whether the problem affects local indication, contacts, remote output or all functions. Compare the model, ambient condition and known reference, then inspect the bulb, pocket, capillary, terminals, supply and receiving scale without disturbing energized CT circuits.',focus:'isolating mechanical, electrical and integration faults in OTI and WTI instruments',contrast:'a remote display error does not automatically prove the local sensing system is faulty',model:'BWY, BWY2, BWR and BWR2',productSlug:'bwr2-transformer-winding-temperature-indicator',checklist:['Local pointer compared with reference','Bulb and pocket condition','Capillary inspection','Contact continuity','Remote loop scale and polarity','WTI CT circuit and converter'],insights:['A flat pointer can indicate sensing-system damage.','A remote-only error can come from wiring or scaling.','Contact faults may be independent of temperature indication.','WTI simulation depends on the CT input under load.','Moisture can affect terminals and mechanisms.','Safe isolation procedures control every diagnostic step.'],featuredAlt:'Technician troubleshooting a transformer temperature indicator',inlineAlt:'Inspection of OTI and WTI capillary terminals and remote signals'},
{slug:'replace-transformer-oil-winding-temperature-indicator',title:'Replace a Transformer OTI or WTI Correctly',description:'Replace a transformer oil or winding temperature indicator by matching model, scale, contacts, signal, CT input, capillary, bulb, thread and mounting.',primaryKeyword:'replace transformer temperature indicator',kind:'installation',category:'Maintenance',answer:'To replace a transformer OTI or WTI, capture the complete existing configuration before removal. Match the full model, scale, contact functions, signal, power, capillary, bulb, thread, mounting and terminal diagram. A WTI replacement also requires CT and compound-transmitter information.',focus:'planning a controlled transformer temperature indicator replacement',contrast:'matching appearance or a partial BWY or BWR family name is not a complete replacement check',model:'BWY, BWY2, BWR and BWR2 replacements',productSlug:'bwr-04-06-winding-temperature-controller',checklist:['Full nameplate photograph','Front and rear installation photos','Terminal and wire labels','Dial scale and set points','Bulb, thread and pocket','CT and converter data for WTI'],insights:['Record wiring before disconnecting the old unit.','Do not bend the new capillary to copy a damaged route.','Compare contact duty as well as contact count.','Verify remote output type and scale.','Function-test cooling, alarm and trip after replacement.','Update drawings and equipment records with the new model.'],featuredAlt:'Replacement oil and winding temperature indicators for transformers',inlineAlt:'Engineer documenting an existing transformer thermometer before retrofit'}
];

const join=(items:string[])=>items.map(item=>`<li>${item}</li>`).join('');
export function renderGuideArticle(blog:Blog){
  const product=`/products/${blog.productSlug}/`;
  const sections=[
    `<section><h2>What does ${blog.primaryKeyword} mean?</h2><div class="answer-block">${blog.answer}</div><p>The useful starting point is ${blog.focus}. A local pointer, an adjustable switch and a remote output are separate functions, even when they share one enclosure.</p><p>For correct model selection, remember that ${blog.contrast}. This affects model choice, set points and the labels used in a control room.</p></section>`,
    `<section><h2>How Should ${blog.primaryKeyword} Be Selected?</h2><p>Selection starts with the transformer and operating purpose. State whether the project is new equipment, a retrofit or a direct replacement. Define who reads the value, which cooling or protection action follows, and whether the instrument must communicate with a panel or supervisory system.</p><p>For ${blog.model}, send the complete model reference rather than a shortened family name. Suffixes can identify switch quantity, transmitter type, remote output, environmental construction or another configuration detail. A visually similar instrument can still be electrically incompatible.</p><ul>${join(blog.checklist)}</ul><p>These inputs allow the supplier and transformer engineer to compare the requested function with a current datasheet, outline drawing and terminal diagram. If any item is unknown, photographs and existing documents are more useful than an assumed value.</p></section>`,
    `<section><h2>How Should the Transformer Temperature Value Be Interpreted?</h2><p>Temperature values describe a defined sensing method and location. They do not represent every part of a transformer at the same instant. Loading, ambient temperature, cooling state, oil circulation and recent operating history all influence the observed value.</p><p>${blog.insights[0]} ${blog.insights[1]} A trend is often more informative than one isolated reading because it shows whether temperature responds normally when load or cooling changes. Unexpected behavior should be assessed with other transformer information rather than explained from one gauge alone.</p><p>Remote systems should preserve the identity of the value. Use explicit tag names, engineering units and scales. Operators should see top oil, simulated winding or another measured variable in the display name, not the vague label transformer temperature.</p></section>`,
    `<section><h2>Which ${blog.model} Configuration Details Matter?</h2><p>${blog.insights[2]} ${blog.insights[3]} The final configuration should connect each requirement to a model feature. If the project needs four contacts, record the purpose of all four. If it needs a remote output, record the signal type, temperature scale, supply and receiving input.</p><p>Mechanical details are equally important. The enclosure must fit the mounting location. The bulb, pocket, thread, insertion depth and capillary must match the transformer arrangement. Outdoor equipment also needs appropriate sealing, cable entry and service access.</p><p>Read the referenced <a href="${product}">${blog.model} product information</a> for planning data, then request the current model-specific documents. Website values should not override the drawing or datasheet issued for an order.</p></section>`,
    `<section><h2>How do contacts support cooling and protection?</h2><p>Adjustable temperature contacts can start a cooling stage, activate a high-temperature alarm or provide an input to trip logic. The control designer assigns the function, voltage, load and interposing relay. The instrument contact rating must be compared with the real circuit, especially for inductive loads.</p><p>Set points come from transformer thermal design and protection coordination. They should not be copied from an unrelated installation. Mechanical switches also have operating tolerance and release differential, so the pointer setting and final switching behavior require verification.</p><p>Commissioning traces every contact from the instrument terminal to the final fan, pump, annunciator or relay input. The approved set point, contact function and test result belong in the equipment record.</p></section>`,
    `<section><h2>Which remote signal is appropriate?</h2><p>Pt100, 4-20 mA and RS485 solve different integration tasks. Pt100 is a resistance signal that needs compatible excitation and lead compensation. A 4-20 mA loop is a powered, scaled process signal. RS485 is a physical digital communication layer that still needs protocol, address and register definitions.</p><p>${blog.insights[4]} ${blog.insights[5]} Define the complete path from field instrument to remote display, PLC, RTU or supervisory system. Include cable, shielding, grounding, isolation, supply and loss-of-signal behavior.</p><p>An end-to-end loop test should compare a representative field value with the local and remote displays. Verify units, scale, alarm mapping and trend label. Store the final configuration so a future replacement can reproduce the signal without guessing.</p></section>`,
    `<section><h2>What installation details affect reliability?</h2><p>A temperature bulb must reach the intended region of its thermometer pocket. The interface should provide suitable thermal coupling while preserving transformer sealing. The capillary is part of the sealed measuring system and cannot be treated as ordinary cable.</p><p>Route the capillary away from sharp edges, concentrated heat, moving parts and locations where it can be crushed. Respect the approved bend radius and support the protective hose against vibration. Manage spare length in a broad, protected coil rather than a tight bundle.</p><p>For powered devices, verify supply before connection. For WTI systems, follow controlled procedures for the CT secondary circuit. For any retrofit, label existing wiring before removal and update drawings after the change.</p></section>`,
    `<section><h2>How should the instrument be commissioned?</h2><p>Commissioning begins with model and document verification. Compare the received instrument with the approved code, scale, contacts, output, supply and mechanical drawing. Inspect the enclosure, dial, terminals, capillary, bulb and supplied accessories before installation.</p><p>Test local indication using the approved method. Operate every adjustable contact and confirm the downstream cooling, alarm or trip response. Loop-test Pt100, 4-20 mA or RS485 values at the receiving system and confirm that the displayed engineering unit and scale are correct.</p><p>Record settings, terminal numbers, remote scale, communication details and results. The record supports maintenance because it shows whether a later difference is in the field instrument, wiring, receiving equipment or transformer operating condition.</p></section>`,
    `<section><h2>What commonly goes wrong?</h2><p>Common errors include ordering by a partial model, confusing OTI with WTI, assuming a contact rating, selecting the wrong signal, overlooking capillary length and treating the mounting thread as the complete mechanical specification. Each error can be prevented by a controlled selection sheet.</p><p>Another problem is publishing or using a generic technical value across several suffixes. Model families can contain meaningful variations. Preserve qualifiers such as referenced, optional and by configuration until the current product document confirms the selected item.</p><p>Finally, do not let the remote system hide the field context. A plausible number can still be mapped to the wrong variable or scale. Clear tag names and end-to-end testing are essential.</p></section>`,
    `<section><h2>${blog.primaryKeyword} Specification Checklist</h2><table><thead><tr><th>Selection area</th><th>Question to answer</th></tr></thead><tbody><tr><td>Measured value</td><td>Top oil, simulated winding or another defined variable?</td></tr><tr><td>Local functions</td><td>Pointer display and how many adjustable contacts?</td></tr><tr><td>Remote interface</td><td>Pt100, 4-20 mA or RS485, with what scale?</td></tr><tr><td>Mechanical interface</td><td>Mounting, bulb, thread, insertion depth and capillary?</td></tr><tr><td>Environment</td><td>Ambient, humidity, altitude and enclosure requirement?</td></tr><tr><td>Documents</td><td>Current datasheet, drawing, terminal diagram and test record?</td></tr></tbody></table><p>Send this information with quantity, destination country and required date. A useful inquiry lets the model and engineering documents be checked before a quotation is treated as final.</p></section>`,
    `<section><h2>Frequently asked technical questions</h2><h3>Can the family name alone define the product?</h3><p>No. The full suffix and project options determine contacts, outputs and other configuration details.</p><h3>Can a top-oil indicator show true winding hot-spot temperature?</h3><p>No. Top oil, simulated winding temperature and direct hot-spot measurement are different quantities.</p><h3>Can contact set points be copied from another transformer?</h3><p>Set points should follow the approved transformer thermal and protection design.</p><h3>What should be provided for a replacement?</h3><p>Send the full nameplate, scale, wiring, mounting, bulb, thread, capillary and remote-interface information.</p></section>`,
    `<section><h2>Request ${blog.model} Technical Documents</h2><p>Review the related <a href="${product}">${blog.model} product page</a>, the <a href="/applications/power-transformer-temperature-monitoring/">power transformer temperature application</a> and the <a href="/applications/transformer-temperature-controller-retrofit/">replacement guide</a>. Email INNO with the full model, specification, quantity and destination country to request a datasheet and quote.</p></section>`
  ];
  return sections.join('');
}

const productLink=(blog:Blog)=>`/products/${blog.productSlug}/`;
const quoteSection=(blog:Blog)=>`<section><h2>Information to Send for a Quote</h2><ul>${join(blog.checklist)}</ul><p>Also include the quantity, destination country, required date and any existing nameplate, wiring or installation drawings. Ask for the current datasheet, outline drawing and terminal diagram for the selected configuration.</p><p>State whether the inquiry is for new transformer production, a planned retrofit or an urgent replacement. This helps the sales and engineering team focus on the correct model, compatibility checks, documentation and packing requirements. Include the transformer rating and installation environment so the proposed instrument can be reviewed in the correct operating context.</p><p><a href="${productLink(blog)}">View the ${blog.model} product page</a> before sending your inquiry.</p></section>`;
const buyerTechnicalReference=(blog:Blog)=>[
  `<section><h2>Define the Temperature Value Before Choosing a Controller</h2><p>A purchasing specification should state exactly what the instrument displays. An oil temperature indicator measures top oil at the transformer thermometer pocket. A traditional winding temperature indicator starts with top-oil temperature and adds a load-current heating effect to simulate winding temperature. These values support different operating decisions and require different model features.</p><p>Use the full term in the equipment list and terminal schedule. Avoid a generic tag such as transformer temperature because it can hide whether the value is measured top oil, simulated winding temperature or a separate direct sensor value. Clear naming also helps operators interpret trends and alarms correctly.</p><p>For ${blog.primaryKeyword}, ask the transformer designer for the required scale, normal operating range and cooling or protection set points. The controller supplier can provide product data, but transformer-specific thermal limits come from the transformer design and approved protection philosophy.</p></section>`,
  `<section><h2>Specify Cooling, Alarm and Trip Contacts</h2><p>Temperature controller contacts are normally assigned to defined functions such as fan start, pump start, high-temperature alarm or a trip relay input. List every required contact separately, including its normal state, setting, connected voltage and downstream load. This is more useful than asking only for a controller with several switches.</p><p>Compare the instrument contact rating with the actual control circuit. Motors, contactor coils and other inductive loads may require an interposing relay. The control-panel designer should also account for switching tolerance and differential so cooling stages operate in the intended sequence without rapid cycling.</p><p>During commissioning, operate each contact and trace the result to the final fan, pump, annunciator or protection input. Record the set point and terminal numbers. This gives purchasing, assembly and maintenance teams one agreed reference for the delivered ${blog.model} configuration.</p></section>`,
  `<section><h2>Choose Pt100, 4-20 mA or RS485 Remote Output</h2><p>Pt100 is a resistance signal for a compatible temperature input or remote indicator. Cable resistance and the selected two-wire, three-wire or four-wire arrangement affect how it is connected. A 4-20 mA output is a scaled current loop and requires a defined temperature range, suitable supply and compatible analog input.</p><p>RS485 identifies the physical communication layer, not the complete communication specification. A digital monitoring inquiry should also identify protocol, baud rate, address method, parity and register information. The device and PLC, RTU or SCADA system must use matching settings.</p><p>Include the receiving equipment in the inquiry. State whether the signal goes to a panel display, PLC analog card, RTU or substation monitoring platform. Ask for the signal scale and wiring diagram, then test the field value against the remote display at more than one point.</p></section>`,
  `<section><h2>Check the Sensing Bulb, Thread and Capillary</h2><p>The sensing bulb must match the transformer thermometer pocket in diameter, insertion length and mounting thread. A thread designation alone does not confirm that the bulb reaches the correct position or fits the existing pocket. For a replacement, provide photographs and dimensions of both the installed instrument and transformer connection.</p><p>Measure the real capillary route from the sensing pocket to the mounting position. Allow enough length for safe routing and service access, but avoid unnecessary tight coils. The capillary is part of a sealed temperature-sensing assembly. It should be protected from crushing, sharp edges, repeated movement and bends tighter than the approved radius.</p><p>Also provide the panel cutout, mounting-hole pattern, viewing direction, cable-entry needs and available service space. These mechanical details often determine whether a proposed replacement can be installed without changing the transformer or control cabinet.</p></section>`,
  `<section><h2>Information Needed for a Replacement Controller</h2><p>Start with the complete existing model code, including every suffix. Add a clear nameplate photo, front view, rear terminals, scale, contact labels and wiring diagram. Record the capillary length, bulb dimensions, mounting thread, enclosure size and mounting-hole positions.</p><p>For a winding temperature indicator, include the current-transformer secondary current and the converter, heater or compound-transmitter information. The thermal simulation must match the transformer design. A replacement that fits mechanically can still indicate the wrong simulated temperature if the current input and heating arrangement are different.</p><p>Identify any planned change, such as replacing Pt100 with 4-20 mA, adding a remote display or changing the contact functions. Ask the supplier to mark differences between the existing unit and proposed model so the panel designer can review wiring changes before the equipment reaches site.</p></section>`,
  `<section><h2>Documents to Request from the Manufacturer or Supplier</h2><p>A useful technical offer includes the complete model code, current datasheet, outline drawing and terminal diagram. The datasheet supports range, accuracy, contact and environmental review. The outline drawing confirms enclosure, mounting, bulb and capillary details. The terminal diagram shows how contacts, supply and remote signals are connected.</p><p>For supplier qualification or tenders, list the management-system certificates, conformity documents, inspection records or country-specific documents required by the project. Tie each requested document to the product or order instead of asking for a general certificate package.</p><p>The commercial inquiry should include quantity, destination, delivery requirement and any inspection or packing requirement. Keeping the technical and commercial scope in one email reduces repeated clarification and makes quotations easier to compare.</p></section>`,
  `<section><h2>Installation and Commissioning Checks</h2><p>Before installation, compare the received nameplate and accessories with the approved order documents. Inspect the dial, pointer, enclosure, terminals, capillary, protective hose, sensing bulb and thread. Verify power before connecting a powered controller, and use the approved safety procedure whenever a current-transformer circuit is involved.</p><p>After installation, check local temperature indication, every cooling or protection contact and every remote output. Confirm that the remote display uses the correct engineering unit and range. For communications, verify address and register mapping. For an analog loop, check the displayed value against the defined signal scale.</p><p>Test the controller under conditions that let the team observe the complete signal path. Confirm terminal labels, contact states, alarm text, trend names and the response expected after a signal failure. Where a cooling stage is controlled by temperature, verify both operation and reset so the equipment does not remain energized or cycle unexpectedly.</p><p>Record the final settings, wiring, remote scaling and functional test. These records allow maintenance teams to separate an instrument problem from a wiring, receiving-system or transformer operating issue, and they provide the information needed for a future ${blog.model} replacement.</p></section>`
].join('');

export function renderModelArticle(blog:Blog){
  return [
    `<section><h2>${blog.model} at a Glance</h2><div class="answer-block">${blog.answer}</div><p>This model guide focuses on ${blog.focus}. Buyers should use the complete model code because ${blog.contrast}.</p></section>`,
    `<section><h2>Specifications to Confirm</h2><table><thead><tr><th>Selection point</th><th>What to check</th></tr></thead><tbody>${blog.checklist.map(item=>`<tr><td>${item}</td><td>Match the purchase specification, existing equipment and current model datasheet.</td></tr>`).join('')}</tbody></table></section>`,
    `<section><h2>Technical Details That Affect the Model Code</h2>${blog.insights.slice(0,3).map(item=>`<p>${item}</p>`).join('')}<p>Do not assume that two instruments with a similar front dial have the same contacts, signal output or capillary assembly.</p></section>`,
    `<section><h2>Replacement and OEM Selection</h2>${blog.insights.slice(3).map(item=>`<p>${item}</p>`).join('')}<p>For replacement work, send clear photos of the nameplate, terminals, mounting and sensing assembly. For new transformer production, send the approved temperature-control schedule and drawings.</p></section>`,
    buyerTechnicalReference(blog),
    quoteSection(blog)
  ].join('');
}

export function renderComparisonArticle(blog:Blog){
  return [
    `<section><h2>Comparison Summary</h2><div class="answer-block">${blog.answer}</div><p>The decision should be based on ${blog.focus}. In particular, ${blog.contrast}.</p></section>`,
    `<section><h2>How the Options Differ</h2><table><thead><tr><th>Buyer question</th><th>How to decide</th></tr></thead><tbody>${blog.checklist.map((item,index)=>`<tr><td>${item}</td><td>${blog.insights[index]}</td></tr>`).join('')}</tbody></table></section>`,
    `<section><h2>Choose by Transformer Function</h2><p>Start with the temperature value required by the transformer design. Then assign the local display, cooling, alarm, trip and remote-monitoring functions. This prevents a familiar model name from being selected for the wrong measurement.</p><p>For retrofit work, compare every terminal and mechanical interface. A family-name match does not establish interchangeability.</p></section>`,
    buyerTechnicalReference(blog),
    quoteSection(blog)
  ].join('');
}

export function renderSystemArticle(blog:Blog){
  return [
    `<section><h2>System Overview</h2><div class="answer-block">${blog.answer}</div><p>The design objective is ${blog.focus}. Keep in mind that ${blog.contrast}.</p></section>`,
    `<section><h2>From Transformer to Control Room</h2><ol><li>Define the sensing point and temperature variable.</li><li>Select local indication and cooling or alarm contacts.</li><li>Choose Pt100, 4-20 mA or RS485 for the receiving system.</li><li>Confirm scale, wiring, power and loss-of-signal behavior.</li><li>Loop-test the local and remote values during commissioning.</li></ol></section>`,
    `<section><h2>Interface and Integration Checks</h2>${blog.insights.map(item=>`<p>${item}</p>`).join('')}</section>`,
    buyerTechnicalReference(blog),
    quoteSection(blog)
  ].join('');
}

export function renderInstallationArticle(blog:Blog){
  return [
    `<section><h2>Before Installation</h2><div class="answer-block">${blog.answer}</div><p>Confirm ${blog.focus}. The installation plan must reflect that ${blog.contrast}.</p><ul>${join(blog.checklist)}</ul></section>`,
    `<section><h2>Installation Sequence</h2><ol><li>Check the full model, scale, contacts and signal against the approved documents.</li><li>Inspect the bulb, capillary, enclosure, terminals and accessories.</li><li>Install the sensing assembly without twisting, crushing or sharply bending the capillary.</li><li>Complete wiring to the approved terminal diagram.</li><li>Test indication, contacts and remote outputs before service.</li></ol></section>`,
    `<section><h2>Common Installation Problems</h2>${blog.insights.slice(0,3).map(item=>`<p>${item}</p>`).join('')}<p>Record contact settings, terminal numbers and remote scaling so future maintenance does not depend on assumptions.</p></section>`,
    `<section><h2>Commissioning Checks</h2>${blog.insights.slice(3).map(item=>`<p>${item}</p>`).join('')}<p>Compare local indication with the receiving display and verify every cooling, alarm or trip path.</p></section>`,
    buyerTechnicalReference(blog),
    quoteSection(blog)
  ].join('');
}

export function articleHtml(blog:Blog){
  if(blog.kind==='model') return renderModelArticle(blog);
  if(blog.kind==='comparison') return renderComparisonArticle(blog);
  if(blog.kind==='system') return renderSystemArticle(blog);
  if(blog.kind==='installation') return renderInstallationArticle(blog);
  return renderGuideArticle(blog);
}
